def _matches_pattern(self, file_path: str, pattern: str) -> bool:
    """
    Check if a file path matches a glob pattern.

    Handles ** (matches any number of directories) and * (matches anything
    in a single path segment).

    Args:
        file_path: The file path to check.
        pattern: The glob pattern to match against.

    Returns:
        True if the file matches the pattern, False otherwise.
    """
    # Handle ** patterns by converting them for fnmatch
    # fnmatch uses *, but ** needs special handling
    if '**' in pattern:
        # Split on ** to get parts
        parts = pattern.split('**')
        if len(parts) == 2:
            # Pattern like "docs/**" or "**/tests"
            prefix = parts[0].rstrip('/')
            suffix = parts[1].lstrip('/')

            if prefix and suffix:
                # Pattern like "src/**/tests"
                # Match: prefix matches start, suffix matches end
                if prefix and not file_path.startswith(prefix):
                    return False
                if suffix and not file_path.endswith(suffix):
                    return False
                # Check that suffix comes after prefix
                rest = file_path[len(prefix):].lstrip('/')
                return rest.endswith(suffix) or fnmatch(rest, f'*{suffix}')
            elif prefix:
                # Pattern like "docs/**"
                return file_path.startswith(prefix)
            elif suffix:
                # Pattern like "**/tests"
                return file_path.endswith(suffix) or fnmatch(file_path, f'*{suffix}')

    # Use fnmatch for standard glob patterns
    return fnmatch(file_path, pattern)

